"use client";

import { type CommandPaletteProps, CommandPalette as CommandPaletteRoot } from "./command-palette";
import { CommandPaletteContent, type CommandPaletteContentProps, type CommandPaletteDensity, type CommandPaletteFrame, commandPaletteContentVariants } from "./command-palette-content";
import { CommandPaletteEmpty, type CommandPaletteEmptyProps } from "./command-palette-empty";
import { CommandPaletteFooter, type CommandPaletteFooterProps } from "./command-palette-footer";
import { CommandPaletteGroup, type CommandPaletteGroupProps } from "./command-palette-group";
import { CommandPaletteInput, type CommandPaletteInputProps } from "./command-palette-input";
import { CommandPaletteItem, type CommandPaletteItemProps, type CommandPaletteItemTone } from "./command-palette-item";
import { CommandPaletteList, type CommandPaletteListProps } from "./command-palette-list";

const CommandPalette = Object.assign(CommandPaletteRoot, {
  Content: CommandPaletteContent,
  Input: CommandPaletteInput,
  List: CommandPaletteList,
  Group: CommandPaletteGroup,
  Item: CommandPaletteItem,
  Empty: CommandPaletteEmpty,
  Footer: CommandPaletteFooter,
});

export { CommandPalette, type CommandPaletteProps };
export { CommandPaletteContent, commandPaletteContentVariants, type CommandPaletteContentProps, type CommandPaletteFrame, type CommandPaletteDensity };
export { CommandPaletteInput, type CommandPaletteInputProps };
export { CommandPaletteList, type CommandPaletteListProps };
export { CommandPaletteGroup, type CommandPaletteGroupProps };
export { CommandPaletteItem, type CommandPaletteItemProps, type CommandPaletteItemTone };
export { CommandPaletteEmpty, type CommandPaletteEmptyProps };
export { CommandPaletteFooter, type CommandPaletteFooterProps };

"use client";

import type { ReactNode } from "react";
import { CommandPaletteContext } from "./command-palette-context";
import {
  type UseCommandPaletteStateOptions,
  useCommandPaletteState,
} from "./use-state";

export interface CommandPaletteProps extends UseCommandPaletteStateOptions {
  children: ReactNode;
}

export function CommandPalette({
  children,
  ...stateProps
}: CommandPaletteProps) {
  const contextValue = useCommandPaletteState(stateProps);

  return (
    <CommandPaletteContext value={contextValue}>
      {children}
    </CommandPaletteContext>
  );
}

"use client";

import { createContext, type KeyboardEvent as ReactKeyboardEvent, type RefObject, useContext } from "react";
import type { CommandPaletteItemRegistration } from "./use-state";

export interface CommandPaletteContextValue {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  highlighted: string | null;
  onHighlightChange: (id: string | null) => void;
  onActivate: (id: string) => void;
  search: string;
  onSearchChange: (value: string) => void;
  shouldFilter: boolean;
  filter: (value: string, search: string) => boolean;
  itemCount: number;
  listId: string;
  listRef: RefObject<HTMLDivElement | null>;
  inputRef: RefObject<HTMLInputElement | null>;
  navKeyDown: (event: ReactKeyboardEvent) => void;
  registerItem: (item: CommandPaletteItemRegistration) => void;
  unregisterItem: (registrationId: string) => void;
}

export const CommandPaletteContext = createContext<CommandPaletteContextValue | undefined>(undefined);

export function useCommandPaletteContext() {
  const context = useContext(CommandPaletteContext);
  if (!context) throw new Error("CommandPalette compound components must be used within a CommandPalette");
  return context;
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import { type ReactNode, useCallback, useState } from "react";
import { useFocusRestore } from "@/hooks/use-focus-restore";
import { cn } from "@/lib/utils";
import { DialogShell } from "../shared/dialog-shell";
import { PortalContainerProvider } from "../shared/portal-context";
import { useCommandPaletteContext } from "./command-palette-context";

export type CommandPaletteFrame = "border" | "viewfinder" | "terminal" | "card" | "none";
export type CommandPaletteDensity = "compact" | "comfortable" | "dense";

export const commandPaletteContentVariants = cva(
  "relative flex flex-col max-h-[80vh] m-auto w-full font-mono",
  {
    variants: {
      size: { sm: "max-w-sm", md: "max-w-xl", lg: "max-w-2xl" },
    },
    defaultVariants: { size: "md" },
  }
);

function getLiveText(search: string, itemCount: number): string {
  if (!search) return "";
  if (itemCount === 0) return "No results";
  return `${itemCount} result${itemCount === 1 ? "" : "s"} available`;
}

export interface CommandPaletteContentProps extends VariantProps<typeof commandPaletteContentVariants> {
  children: ReactNode;
  className?: string;
  label?: string;
  frame?: CommandPaletteFrame | null;
  density?: CommandPaletteDensity | null;
}

export function CommandPaletteContent({
  children,
  className,
  size,
  frame,
  density,
  label = "Command palette",
}: CommandPaletteContentProps) {
  const { open, onOpenChange, search, onSearchChange, itemCount, inputRef } = useCommandPaletteContext();
  const [container, setContainer] = useState<Element | null>(null);
  const focusRestore = useFocusRestore({ restoreOnUnmount: false });

  const resolvedFrame = frame ?? "border";
  const resolvedDensity = density ?? "compact";

  // Stable identity for DialogShell's dialogRef callback so the underlying ref isn't re-attached on every render.
  const setDialogRef = useCallback((node: HTMLDialogElement | null) => {
    setContainer(node);
  }, []);

  // Stable identity for DialogShell's onAfterShowModal so focus runs only on open transitions.
  const focusSearchInput = useCallback(() => {
    inputRef.current?.focus();
  }, [inputRef]);

  return (
    <DialogShell
      open={open}
      dialogRef={setDialogRef}
      onBeforeShowModal={focusRestore.capture}
      onAfterShowModal={focusSearchInput}
      onBackdropClick={() => onOpenChange(false)}
      onCancel={() => search ? onSearchChange("") : onOpenChange(false)}
      onClose={focusRestore.restore}
      className={cn(commandPaletteContentVariants({ size }), className)}
      data-slot="command-palette-content"
      data-frame={resolvedFrame}
      data-density={resolvedDensity}
      aria-modal="true"
      aria-label={label}
    >
      <PortalContainerProvider container={container}>
        {resolvedFrame === "viewfinder" ? (
          <span aria-hidden="true" className="cp-corners" />
        ) : null}
        {children}
        {/* biome-ignore lint/a11y/useSemanticElements: role="status" is the sr-only results-count live region; <output> carries form-association semantics that do not fit here. */}
        <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">
          {getLiveText(search, itemCount)}
        </div>
      </PortalContainerProvider>
    </DialogShell>
  );
}

"use client";

import type { KeyboardEvent as ReactKeyboardEvent, ReactNode, Ref } from "react";
import { Kbd } from "@/components/ui/kbd";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";
import { getCommandPaletteItemDomId } from "./use-state";

const INPUT_NAVIGATION_KEYS = new Set(["ArrowUp", "ArrowDown", "Enter"]);

export interface CommandPaletteInputProps {
  placeholder?: string;
  label?: string;
  prefix?: ReactNode;
  suffix?: ReactNode;
  onKeyDown?: (event: ReactKeyboardEvent<HTMLInputElement>) => void;
  className?: string;
  ref?: Ref<HTMLInputElement>;
}

export function CommandPaletteInput({
  placeholder = "Type a command…",
  label = "Command search",
  prefix,
  suffix,
  onKeyDown,
  className,
  ref,
}: CommandPaletteInputProps) {
  const { open, search, onSearchChange, navKeyDown, highlighted, listId, inputRef } = useCommandPaletteContext();

  return (
    <div data-slot="command-palette-input" className={cn(className)}>
      {prefix !== undefined ? (
        <span data-slot="command-palette-input-prefix">{prefix}</span>
      ) : (
        <span data-slot="command-palette-input-prefix" data-default aria-hidden="true" />
      )}
      <input
        ref={ref ? composeRefs(inputRef, ref) : inputRef}
        type="text"
        role="combobox"
        aria-label={label}
        aria-expanded={open}
        aria-autocomplete="list"
        aria-controls={listId}
        aria-activedescendant={highlighted !== null ? getCommandPaletteItemDomId(listId, highlighted) : undefined}
        value={search}
        onChange={(e) => onSearchChange(e.target.value)}
        onKeyDown={(e) => {
          onKeyDown?.(e);
          if (e.defaultPrevented) return;
          if (e.key === "Escape") {
            if (search) {
              e.preventDefault();
              onSearchChange("");
            }
            return;
          }
          if (e.key === " ") return;
          if (INPUT_NAVIGATION_KEYS.has(e.key)) navKeyDown(e);
        }}
        placeholder={placeholder}
        className="flex-1 min-w-0 bg-transparent border-0 outline-none p-0 text-foreground placeholder-muted-foreground/70 font-mono caret-foreground"
        style={{ fontSize: "var(--cp-text-size)" }}
      />
      {suffix !== undefined ? (
        <span data-slot="command-palette-input-suffix">{suffix}</span>
      ) : (
        <span data-slot="command-palette-input-suffix">
          <Kbd size="sm">Esc</Kbd>
        </span>
      )}
    </div>
  );
}

"use client";

import type { ReactNode, Ref } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";

export interface CommandPaletteListProps {
  children: ReactNode;
  className?: string;
  "aria-label"?: string;
  ref?: Ref<HTMLDivElement>;
}

export function CommandPaletteList({ children, className, "aria-label": ariaLabel = "Command results", ref }: CommandPaletteListProps) {
  const { listRef, listId } = useCommandPaletteContext();
  return (
    <div
      id={listId}
      ref={composeRefs(listRef, ref)}
      role="listbox"
      aria-label={ariaLabel}
      data-slot="command-palette-list"
      className={cn("flex-1 overflow-y-auto", className)}
    >
      {children}
    </div>
  );
}

"use client";

import { type ReactNode, useId } from "react";
import { cn } from "@/lib/utils";

export interface CommandPaletteGroupProps {
  heading: ReactNode;
  children: ReactNode;
  className?: string;
}

export function CommandPaletteGroup({ heading, children, className }: CommandPaletteGroupProps) {
  const headingId = useId();
  return (
    // biome-ignore lint/a11y/useSemanticElements: role="group" labels a related set of command options; <fieldset> is for form controls and is not appropriate here.
    <div
      role="group"
      aria-labelledby={headingId}
      data-slot="command-palette-group"
      className={cn("hidden has-[[role=option]]:block", className)}
    >
      <div id={headingId} data-slot="command-palette-group-heading">{heading}</div>
      <div>{children}</div>
    </div>
  );
}

"use client";

import type { ReactNode } from "react";
import { useCommandPaletteContext } from "./command-palette-context";

export interface CommandPaletteEmptyProps {
  children: ReactNode;
  className?: string;
}

export function CommandPaletteEmpty({ children, className }: CommandPaletteEmptyProps) {
  const { itemCount, search } = useCommandPaletteContext();
  if (itemCount > 0 || !search) return null;
  return (
    // biome-ignore lint/a11y/useSemanticElements: role="status" is the empty-results live region; <output> carries form-association semantics that do not fit here.
    <div role="status" aria-live="polite" data-slot="command-palette-empty" className={className}>
      {children}
    </div>
  );
}

"use client";

import type { ReactNode } from "react";

export interface CommandPaletteFooterProps {
  children: ReactNode;
  className?: string;
}

export function CommandPaletteFooter({ children, className }: CommandPaletteFooterProps) {
  return (
    <div data-slot="command-palette-footer" className={className}>
      {children}
    </div>
  );
}

"use client";

import { type ComponentPropsWithRef, type MouseEvent, type ReactNode, useId, useLayoutEffect, useRef } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { useCommandPaletteContext } from "./command-palette-context";
import { getCommandPaletteItemDomId } from "./use-state";

export type CommandPaletteItemTone =
  | "neutral"
  | "nav"
  | "action"
  | "settings"
  | "destructive"
  | "ai";

export interface CommandPaletteItemProps
  extends Omit<ComponentPropsWithRef<"div">, "children" | "id" | "onSelect"> {
  id: string;
  value?: string;
  icon?: ReactNode;
  shortcut?: string;
  tone?: CommandPaletteItemTone;
  onSelect?: () => void;
  disabled?: boolean;
  children: ReactNode;
}

export function CommandPaletteItem({
  id,
  value,
  icon,
  shortcut,
  tone = "neutral",
  onSelect,
  disabled = false,
  children,
  className,
  ref,
  onClick,
  onMouseMove,
  ...props
}: CommandPaletteItemProps) {
  const {
    highlighted,
    onHighlightChange,
    onActivate,
    search,
    shouldFilter,
    filter,
    listId,
    registerItem,
    unregisterItem,
  } = useCommandPaletteContext();
  const registrationId = useId();
  const rootRef = useRef<HTMLDivElement>(null);

  const searchValue = value ?? id;
  const isVisible = !shouldFilter || !search || filter(searchValue, search);

  useLayoutEffect(() => {
    registerItem({
      registrationId,
      id,
      value: searchValue,
      disabled: disabled || !isVisible,
      onSelect: disabled ? undefined : onSelect,
      element: isVisible ? rootRef.current : null,
    });
    return () => unregisterItem(registrationId);
  }, [disabled, id, isVisible, onSelect, registerItem, registrationId, searchValue, unregisterItem]);

  if (!isVisible) return null;

  const isHighlighted = highlighted === id;

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (!event.defaultPrevented && !disabled) onActivate(id);
  };

  const handleMouseMove = (event: MouseEvent<HTMLDivElement>) => {
    onMouseMove?.(event);
    if (event.defaultPrevented || disabled) return;
    if (highlighted !== id) onHighlightChange(id);
  };

  return (
    // biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA combobox/listbox pattern — option stays non-focusable while the input keeps focus and aria-activedescendant tracks the active option.
    // biome-ignore lint/a11y/useKeyWithClickEvents: Enter activation is handled centrally by the command palette input, not per option.
    <div
      {...props}
      ref={composeRefs(rootRef, ref)}
      id={getCommandPaletteItemDomId(listId, id)}
      role="option"
      data-slot="command-palette-item"
      data-value={id}
      data-tone={tone}
      aria-selected={isHighlighted}
      aria-disabled={disabled || undefined}
      onClick={handleClick}
      onMouseMove={handleMouseMove}
      className={className}
    >
      {icon !== undefined && (
        <span data-slot="command-palette-item-icon">{icon}</span>
      )}
      <span data-slot="command-palette-item-label">{children}</span>
      {shortcut ? (
        <span data-slot="command-palette-item-shortcut">{shortcut}</span>
      ) : null}
    </div>
  );
}

"use client";

import { Children, type ReactNode } from "react";
import { useCommandPaletteContext } from "./command-palette-context";
import { CommandPaletteItem, type CommandPaletteItemProps, type CommandPaletteItemTone } from "./command-palette-item";

const TONE_RULES: ReadonlyArray<readonly [RegExp, CommandPaletteItemTone]> = [
  [/^(delete|remove|reset|drop|destroy|log\s*out|sign\s*out)\b/i, "destructive"],
  [/^(go to|open|jump|navigate|switch|view)\b/i, "nav"],
  [/^(toggle|enable|disable|set|configure|preferences|settings)\b/i, "settings"],
  [/^(ask|generate|summari[sz]e|explain|chat|ai)\b/i, "ai"],
  [/^(run|exec|build|test|deploy|create|new|add|export|import|copy)\b/i, "action"],
];

export function categorize(value: string): CommandPaletteItemTone {
  const trimmed = value.trim();
  for (const [pattern, tone] of TONE_RULES) {
    if (pattern.test(trimmed)) return tone;
  }
  return "neutral";
}

export function matchPositions(value: string, search: string): number[] {
  if (!search) return [];
  const lowerValue = value.toLowerCase();
  const lowerSearch = search.toLowerCase();
  const contiguous = lowerValue.indexOf(lowerSearch);
  if (contiguous !== -1) {
    return Array.from({ length: lowerSearch.length }, (_, i) => contiguous + i);
  }
  const positions: number[] = [];
  let cursor = 0;
  for (const char of lowerSearch) {
    const index = lowerValue.indexOf(char, cursor);
    if (index === -1) return [];
    positions.push(index);
    cursor = index + 1;
  }
  return positions;
}

function renderWithMatches(value: string, search: string): ReactNode {
  const positions = matchPositions(value, search);
  if (positions.length === 0) return value;
  const set = new Set(positions);
  const nodes: ReactNode[] = [];
  for (let i = 0; i < value.length; i++) {
    const char = value[i] ?? "";
    if (set.has(i)) {
      nodes.push(
        <mark key={i} data-slot="command-palette-item-match">{char}</mark>
      );
    } else {
      nodes.push(char);
    }
  }
  return nodes;
}

function extractText(children: ReactNode): string {
  let text = "";
  Children.forEach(children, (child) => {
    if (typeof child === "string" || typeof child === "number") {
      text += String(child);
    }
  });
  return text;
}

// Children are highlight-safe when extractText recovers the full descendant
// text — i.e. nothing was dropped by skipping non-string nodes. For mixed
// content (icons, <strong>, etc.) we must render children untouched to avoid
// silent content loss.
function isPureText(children: ReactNode): boolean {
  if (typeof children === "string" || typeof children === "number") return true;
  if (Array.isArray(children)) return children.every(isPureText);
  return false;
}

export interface CommandPaletteHighlightItemProps extends Omit<CommandPaletteItemProps, "tone"> {
  tone?: CommandPaletteItemTone;
  label?: string;
}

export function CommandPaletteHighlightItem({
  tone,
  value,
  label,
  children,
  ...rest
}: CommandPaletteHighlightItemProps) {
  const { search } = useCommandPaletteContext();
  const renderedChildren = children ?? label;
  const childrenIsPureText = children !== undefined && isPureText(children);
  const labelText = label ?? (childrenIsPureText ? extractText(children) : "");
  const searchValue = value ?? labelText;
  const resolvedTone = tone ?? categorize(labelText);
  return (
    <CommandPaletteItem {...rest} value={searchValue} tone={resolvedTone}>
      {childrenIsPureText && search
        ? renderWithMatches(extractText(children), search)
        : renderedChildren}
    </CommandPaletteItem>
  );
}

export {
  CommandPaletteHighlightItem,
  type CommandPaletteHighlightItemProps,
  categorize,
  matchPositions,
} from "./command-palette-highlight";

"use client";

import { useCallback, useId, useMemo, useRef, useState } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useNavigation } from "@/hooks/use-navigation";
import { matchesSearch } from "@/lib/search";
import { sortSelectableCollectionItems } from "@/lib/selectable-collection";
import type { CommandPaletteContextValue } from "./command-palette-context";

const defaultFilter = matchesSearch;

export function getCommandPaletteItemDomId(listId: string, id: string): string {
  const encoded = Array.from(id, (char) => char.codePointAt(0)?.toString(36) ?? "0").join("-");
  return `${listId}-item-${encoded || "empty"}`;
}

export interface UseCommandPaletteStateOptions {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  search?: string;
  onSearchChange?: (value: string) => void;
  highlighted?: string | null;
  onHighlightChange?: (id: string | null) => void;
  onActivate?: (id: string) => void;
  shouldFilter?: boolean;
  filter?: (value: string, search: string) => boolean;
}

export function useCommandPaletteState({
  open: controlledOpen,
  onOpenChange,
  search: controlledSearch,
  onSearchChange: controlledOnSearchChange,
  highlighted: controlledHighlighted,
  onHighlightChange,
  onActivate,
  shouldFilter = true,
  filter: filterProp,
}: UseCommandPaletteStateOptions): CommandPaletteContextValue {
  const [registeredItems, setRegisteredItems] = useState<CommandPaletteItemRegistration[]>([]);
  const filter = filterProp ?? defaultFilter;
  const [isOpen, setIsOpen] = useControllableState({ value: controlledOpen, defaultValue: false, onChange: onOpenChange });
  const [search, setSearch] = useControllableState({ value: controlledSearch, defaultValue: "", onChange: controlledOnSearchChange });
  const [highlighted, setHighlighted, isHighlightedControlled] = useControllableState<string | null>({
    value: controlledHighlighted,
    controlled: controlledHighlighted !== undefined,
    defaultValue: null,
    onChange: onHighlightChange,
  });
  const listRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const paletteId = useId();
  const activeItems = useMemo(
    () => sortSelectableCollectionItems(registeredItems)
      .filter((item) => !item.disabled && item.element !== null),
    [registeredItems],
  );
  const itemCallbacks = useMemo(
    () => new Map(activeItems.map((item) => [item.id, item.onSelect])),
    [activeItems],
  );
  const itemIds = useMemo(() => activeItems.map((item) => item.id), [activeItems]);

  const handleOpenChange = useCallback((next: boolean) => {
    if (!next) setSearch("");
    setIsOpen(next);
  }, [setIsOpen, setSearch]);

  const handleActivate = useCallback((id: string) => {
    itemCallbacks.get(id)?.();
    onActivate?.(id);
    handleOpenChange(false);
  }, [handleOpenChange, itemCallbacks, onActivate]);

  const registerItem = useCallback((item: CommandPaletteItemRegistration) => {
    setRegisteredItems((current) => {
      const existingIndex = current.findIndex((candidate) => candidate.registrationId === item.registrationId);
      const next = existingIndex === -1 ? [...current, item] : [...current];
      if (existingIndex !== -1) next[existingIndex] = item;
      return next;
    });
  }, []);

  const unregisterItem = useCallback((registrationId: string) => {
    setRegisteredItems((current) => current.filter((item) => item.registrationId !== registrationId));
  }, []);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef: listRef,
    role: "option",
    wrap: true,
    highlighted: getEffectiveHighlighted(highlighted, itemIds, isHighlightedControlled),
    onHighlightChange: setHighlighted,
    onEnter: handleActivate,
    enabled: isOpen,
    scopeToContainer: true,
  });

  return useMemo(() => ({
    open: isOpen, onOpenChange: handleOpenChange, highlighted: getEffectiveHighlighted(highlighted, itemIds, isHighlightedControlled),
    onHighlightChange: setHighlighted,
    onActivate: handleActivate, search, onSearchChange: setSearch,
    shouldFilter, filter, itemCount: itemIds.length,
    listId: `${paletteId}-list`, listRef, inputRef, navKeyDown, registerItem, unregisterItem,
  }), [isOpen, handleOpenChange, handleActivate, highlighted, itemIds, isHighlightedControlled, setHighlighted, search, setSearch, shouldFilter, filter, paletteId, navKeyDown, registerItem, unregisterItem]);
}

export interface CommandPaletteItemMetadata {
  id: string;
  value: string;
  disabled: boolean;
  onSelect?: () => void;
}

export interface CommandPaletteItemRegistration extends CommandPaletteItemMetadata {
  registrationId: string;
  element: HTMLElement | null;
}

function getEffectiveHighlighted(
  highlighted: string | null,
  items: readonly string[],
  isControlled: boolean,
): string | null {
  if (highlighted !== null && items.includes(highlighted)) return highlighted;
  if (isControlled) return null;
  return items[0] ?? null;
}

/*
 * CommandPalette primitive styles. Two orthogonal axes drive visual chrome
 * via data-attribute selectors on [data-slot="command-palette-content"]:
 *   [data-frame] = border | viewfinder | terminal | card | none
 *   [data-density] = compact | comfortable | dense
 *
 * Density controls a CSS-variable surface read by every inner slot:
 *   --cp-row-h, --cp-row-px, --cp-row-py,
 *   --cp-input-py, --cp-input-px,
 *   --cp-list-p,
 *   --cp-heading-size, --cp-prefix-size, --cp-text-size
 *
 * Tone tokens (item left bar + icon tint) read from semantic theme tokens.
 */
@layer components {
  [data-slot="command-palette-content"] {
    --cp-bg: var(--background);
    --cp-fg: var(--foreground);
    --cp-border: var(--border);
    --cp-border-soft: color-mix(in oklab, var(--border) 60%, transparent);
    --cp-muted: var(--muted-foreground);
    --cp-prefix-content: ">";
    --cp-tone-nav: var(--info);
    --cp-tone-action: var(--success);
    --cp-tone-settings: var(--warning);
    --cp-tone-destructive: var(--destructive);
    --cp-tone-ai: var(--accent);

    position: relative;
    background: var(--cp-bg);
    color: var(--cp-fg);
  }

  /* Density: compact (default) */
  [data-slot="command-palette-content"][data-density="compact"] {
    --cp-row-h: 32px;
    --cp-row-px: 12px;
    --cp-row-py: 8px;
    --cp-input-py: 12px;
    --cp-input-px: 16px;
    --cp-list-p: 6px;
    --cp-heading-size: 12px;
    --cp-prefix-size: 14px;
    --cp-text-size: 14px;
  }

  /* Density: comfortable */
  [data-slot="command-palette-content"][data-density="comfortable"] {
    --cp-row-h: 40px;
    --cp-row-px: 12px;
    --cp-row-py: 10px;
    --cp-input-py: 16px;
    --cp-input-px: 20px;
    --cp-list-p: 8px;
    --cp-heading-size: 12px;
    --cp-prefix-size: 15px;
    --cp-text-size: 14px;
  }

  /* Density: dense */
  [data-slot="command-palette-content"][data-density="dense"] {
    --cp-row-h: 24px;
    --cp-row-px: 8px;
    --cp-row-py: 3px;
    --cp-input-py: 8px;
    --cp-input-px: 12px;
    --cp-list-p: 4px;
    --cp-heading-size: 11px;
    --cp-prefix-size: 13px;
    --cp-text-size: 13px;
  }

  /* Frame: border (default) — single 1px hairline. */
  [data-slot="command-palette-content"][data-frame="border"] {
    border: 1px solid var(--cp-border);
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  /* Frame: viewfinder — no border, four corner brackets. */
  [data-slot="command-palette-content"][data-frame="viewfinder"] {
    border: 0;
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"]::after,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    border: 0 solid var(--cp-fg);
    pointer-events: none;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before {
    top: -1px;
    left: -1px;
    border-top-width: 2px;
    border-left-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::after {
    top: -1px;
    right: -1px;
    border-top-width: 2px;
    border-right-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before {
    bottom: -1px;
    left: -1px;
    border-bottom-width: 2px;
    border-left-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    bottom: -1px;
    right: -1px;
    border-bottom-width: 2px;
    border-right-width: 2px;
  }

  /* Frame: terminal — top + bottom 2px rules, no side borders. */
  [data-slot="command-palette-content"][data-frame="terminal"] {
    border: 0;
    border-top: 2px solid var(--cp-fg);
    border-bottom: 2px solid var(--cp-fg);
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
    --cp-prefix-content: "$";
  }

  [data-slot="command-palette-content"][data-frame="terminal"] [data-slot="command-palette-input-prefix"] {
    color: var(--cp-fg);
    font-weight: 700;
  }

  /* Frame: card — Linear-ish rounded shell with a subtle gradient surface. */
  [data-slot="command-palette-content"][data-frame="card"] {
    border: 1px solid var(--cp-border);
    border-radius: 8px;
    background: linear-gradient(140deg, color-mix(in oklab, var(--cp-fg) 6%, var(--cp-bg)) 0%, var(--cp-bg) 100%);
    box-shadow: 0 30px 80px oklch(0% 0 0 / 0.7);
    overflow: hidden;
  }

  /* Frame: none — bare. */
  [data-slot="command-palette-content"][data-frame="none"] {
    border: 0;
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  /* Input row */
  [data-slot="command-palette-input"] {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: var(--cp-input-py) var(--cp-input-px);
    border-bottom: 1px solid var(--cp-border-soft);
  }

  [data-slot="command-palette-input-prefix"] {
    color: var(--cp-muted);
    font-size: var(--cp-prefix-size);
    user-select: none;
    flex-shrink: 0;
  }

  [data-slot="command-palette-input-prefix"][data-default]::before {
    content: var(--cp-prefix-content);
  }

  [data-slot="command-palette-input-suffix"] {
    display: inline-flex;
    align-items: center;
    flex-shrink: 0;
  }

  /* List */
  [data-slot="command-palette-list"] {
    padding: var(--cp-list-p);
  }

  /* Group */
  [data-slot="command-palette-group-heading"] {
    padding: 8px 10px 4px;
    font-size: var(--cp-heading-size);
    font-weight: 500;
    color: var(--cp-muted);
  }

  /* Frame-scoped heading typography. Mirrors V2/V3 in the variants preview. */
  [data-slot="command-palette-content"][data-frame="viewfinder"] [data-slot="command-palette-group-heading"] {
    text-transform: uppercase;
    letter-spacing: 0.06em;
    font-size: 11px;
  }

  [data-slot="command-palette-content"][data-frame="terminal"] [data-slot="command-palette-group-heading"] {
    padding: 6px var(--cp-input-px) 2px;
    font-weight: 400;
  }

  /* Item */
  [data-slot="command-palette-item"] {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: var(--cp-row-py) var(--cp-row-px);
    min-height: var(--cp-row-h);
    font-size: var(--cp-text-size);
    color: var(--cp-fg);
    cursor: pointer;
    user-select: none;
    position: relative;
  }

  [data-slot="command-palette-item"][aria-disabled="true"] {
    opacity: 0.5;
    cursor: not-allowed;
  }

  [data-slot="command-palette-item"][aria-selected="true"] {
    background: color-mix(in oklab, var(--cp-fg) 7%, transparent);
    color: var(--cp-fg);
  }

  /* Viewfinder frame replaces the selection tint with a 2px left accent bar
     (matches the dialog viewfinder language). Use ::after so it doesn't
     collide with the tone bar at [data-tone]:not([data-tone="neutral"])::before. */
  [data-slot="command-palette-content"][data-frame="viewfinder"] [data-slot="command-palette-item"][aria-selected="true"] {
    background: transparent;
    font-weight: 500;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] [data-slot="command-palette-item"][aria-selected="true"]::after {
    content: "";
    position: absolute;
    left: 0;
    top: 4px;
    bottom: 4px;
    width: 2px;
    background: var(--cp-fg);
    pointer-events: none;
  }

  /* Terminal frame inverts selection (white-on-black). */
  [data-slot="command-palette-content"][data-frame="terminal"] [data-slot="command-palette-item"][aria-selected="true"] {
    background: var(--cp-fg);
    color: var(--cp-bg);
    font-weight: 500;
  }

  /* Card frame: rows float inside the list padding with a rounded selection. */
  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-item"] {
    margin: 0 var(--cp-list-p);
    border-radius: 6px;
  }

  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-item"][aria-selected="true"] {
    background: color-mix(in oklab, var(--cp-fg) 8%, transparent);
  }

  [data-slot="command-palette-item-icon"] {
    display: inline-flex;
    align-items: center;
    color: var(--cp-muted);
    flex-shrink: 0;
  }

  [data-slot="command-palette-item-label"] {
    flex: 1 1 auto;
    min-width: 0;
  }

  [data-slot="command-palette-item-shortcut"] {
    color: var(--cp-muted);
    font-size: 11px;
    flex-shrink: 0;
  }

  /* Tones: 2px left bar + icon tint. Label color inherits to preserve readability. */
  [data-slot="command-palette-item"][data-tone]:not([data-tone="neutral"])::before {
    content: "";
    position: absolute;
    left: 4px;
    top: 8px;
    bottom: 8px;
    width: 2px;
  }

  [data-slot="command-palette-item"][data-tone="nav"]::before { background: var(--cp-tone-nav); }
  [data-slot="command-palette-item"][data-tone="action"]::before { background: var(--cp-tone-action); }
  [data-slot="command-palette-item"][data-tone="settings"]::before { background: var(--cp-tone-settings); }
  [data-slot="command-palette-item"][data-tone="destructive"]::before { background: var(--cp-tone-destructive); }
  [data-slot="command-palette-item"][data-tone="ai"]::before { background: var(--cp-tone-ai); }

  /* Hide the tone bar on disabled rows; the muted row body already signals state. */
  [data-slot="command-palette-item"][aria-disabled="true"]::before { display: none; }

  [data-slot="command-palette-item"][data-tone="nav"] [data-slot="command-palette-item-icon"] { color: var(--cp-tone-nav); }
  [data-slot="command-palette-item"][data-tone="action"] [data-slot="command-palette-item-icon"] { color: var(--cp-tone-action); }
  [data-slot="command-palette-item"][data-tone="settings"] [data-slot="command-palette-item-icon"] { color: var(--cp-tone-settings); }
  [data-slot="command-palette-item"][data-tone="destructive"] [data-slot="command-palette-item-icon"] { color: var(--cp-tone-destructive); }
  [data-slot="command-palette-item"][data-tone="ai"] [data-slot="command-palette-item-icon"] { color: var(--cp-tone-ai); }

  /* Under the terminal frame's inverted selection (bg: --cp-fg, color: --cp-bg)
     tones lose contrast: in the dark-mode minimal theme several tone tokens
     resolve to the same color as --foreground (e.g. --success → --tui-green
     → #e5e5e5 = white), which would render the 2px bar and icon invisible
     against the white selection background. Re-tint both to --cp-bg so they
     remain visible without re-coloring the label. */
  [data-slot="command-palette-content"][data-frame="terminal"] [data-slot="command-palette-item"][aria-selected="true"] [data-slot="command-palette-item-icon"] {
    color: var(--cp-bg);
  }

  [data-slot="command-palette-content"][data-frame="terminal"] [data-slot="command-palette-item"][aria-selected="true"][data-tone]:not([data-tone="neutral"])::before {
    background: var(--cp-bg);
  }

  /* Match highlight */
  [data-slot="command-palette-item-match"] {
    color: var(--cp-fg);
    background: transparent;
    font-weight: 600;
    text-decoration: underline;
    text-underline-offset: 2px;
    text-decoration-thickness: 1px;
  }

  /* Empty state */
  [data-slot="command-palette-empty"] {
    padding: 24px 12px;
    text-align: center;
    font-size: var(--cp-text-size);
    color: var(--cp-muted);
  }

  /* Footer */
  [data-slot="command-palette-footer"] {
    display: flex;
    align-items: center;
    gap: 16px;
    flex-wrap: wrap;
    padding: 8px 12px;
    border-top: 1px solid var(--cp-border-soft);
    font-size: 11px;
    color: var(--cp-muted);
    user-select: none;
  }

  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-footer"] {
    background: color-mix(in oklab, black 25%, transparent);
    border-top: 1px solid color-mix(in oklab, var(--cp-fg) 8%, transparent);
  }
}

@media (forced-colors: active) {
  [data-slot="command-palette-content"][data-frame="border"],
  [data-slot="command-palette-content"][data-frame="terminal"],
  [data-slot="command-palette-content"][data-frame="card"] {
    border-color: CanvasText;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"]::after,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    border-color: CanvasText;
  }
}
